1	// Solar panels — OWNED by Dev A
2	// Placement strategy (GLB-driven, baked positions are NOT used for layout):
3	//   1. After the GLB is fully visible (glbStable), sample its XZ bbox with a
4	//      grid of vertical raycasts at panel-pitch resolution. Each successful
5	//      hit on a roof-like face (normal.y above threshold) becomes a candidate.
6	//   2. Score each candidate by tilt + flatness so the algorithm prefers the
7	//      part of the roof a real installer would target.
8	//   3. Greedy placement walks candidates from best score down, accepting one
9	//      only if (a) all four corners land on the same roof slope (no eave or
10	//      ridge overhang, no straddling two pitches), (b) it doesn't overlap a
11	//      panel already placed, (c) it isn't on a baked obstruction (chimney,
12	//      dormer, vent).
13	//   4. Stops once we hit the count requested by the k-NN sizer (design.
14	//      modulePositions.length).
15	//
16	// Reveal animation: the orchestrator ticks `placedCount` up from 0 to the
17	// total module count over a few seconds. We slice the projected positions
18	// array by that count, and each panel mesh, on mount, "drops" along its
19	// (face) normal from ~1.5 m above the final spot down onto the roof with an
20	// ease-out cubic — so panels appear to land one by one in order.
21	
22	'use client';
23	
24	import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
25	import { useFrame, useThree, type ThreeEvent } from '@react-three/fiber';
26	import {
27	  Box3,
28	  Group,
29	  Mesh,
30	  Object3D,
31	  Quaternion,
32	  Raycaster,
33	  Vector3,
34	} from 'three';
35	import { useStore, type EditablePanel } from '@/lib/store';
36	import { useHouseGeometry } from './HouseGeometry';
37	
38	// Real-world panel SKU catalogue. Each variant is a market-available form
39	// factor; the placement algorithm tries the full-size variant first and
40	// falls back to compact / mini if the roof can't fit the target count.
41	//   • AIKO Comet / Trina Vertex S+ — full residential 470-475 W.
42	//   • Half-cell 220 W — compact module for tight roof zones.
43	//   • Mini 120 W — fills the leftover slivers between dormers / chimneys.
44	// Wattage is what's used to convert the kWp target into a panel count,
45	// so smaller panels naturally produce a denser layout.
46	interface PanelVariant {
47	  name: string;
48	  size: [number, number, number];
49	  wattPeak: number;
50	}
51	const PANEL_VARIANT_FULL_AIKO: PanelVariant = {
52	  name: 'AIKO 475 W',
53	  size: [1.722, 0.03, 1.134],
54	  wattPeak: 475,
55	};
56	const PANEL_VARIANT_FULL_TRINA: PanelVariant = {
57	  name: 'Trina 475 W',
58	  size: [1.762, 0.03, 1.134],
59	  wattPeak: 475,
60	};
61	const PANEL_VARIANT_COMPACT: PanelVariant = {
62	  name: 'Half-cell 220 W',
63	  size: [1.10, 0.03, 0.70],
64	  wattPeak: 220,
65	};
66	const PANEL_VARIANT_MINI: PanelVariant = {
67	  name: 'Mini 120 W',
68	  size: [0.78, 0.03, 0.55],
69	  wattPeak: 120,
70	};
71	// Distance from the raycast hit point (roof surface) to the panel mesh
72	// CENTRE along the surface normal. Real photovoltaic panels sit on rail
73	// systems that lift them 10-15 cm above the tile. Half-thickness of the
74	// AIKO datasheet (30 mm) is 15 mm, so with LIFT = 0.13 m the panel BASE
75	// floats ~11.5 cm above the roof — visibly mounted, not embedded.
76	const PANEL_LIFT_M = 0.13;
77	const PANEL_COLOR = '#1a3a6e';        // PV cell deep blue (AIKO N-type look)
78	const PANEL_FRAME_COLOR = '#2a2f3a';  // anodised aluminium dark grey
79	const DROP_HEIGHT_M = 1.5;
80	const DROP_DURATION_MS = 550;
81	/** Above-roof origin for downward raycasts (must comfortably exceed any
82	 *  recentred GLB height). */
83	const RAY_ORIGIN_Y = 60;
84	/** Reject hits whose normal Y is below this threshold (= not roof-like:
85	 *  walls, ground plane, vertical surfaces). Kept moderate (0.3) so shallow
86	 *  Hunyuan slopes register as roof but vertical faces don't. */
87	const ROOF_NORMAL_Y_MIN = 0.3;
88	/** Two probe hits are considered to be on the same pitch if their normals
89	 *  agree by at least this dot product. Below ~0.85 means the angle between
90	 *  them exceeds ~30° — almost certainly different surfaces (dormer side,
91	 *  chimney face, window frame). */
92	const SAME_PITCH_DOT = 0.85;
93	/** A probe is considered an OBSTACLE relative to the candidate centre if
94	 *  the GLB surface at that probe deviates more than this much (along the
95	 *  panel normal) — picks up chimneys, dormer cubes, antennas, skylight
96	 *  frames protruding above OR recessed below the roof tiles. Real Velux
97	 *  skylights protrude 3–10 cm and recess 2-4 cm at the glass; 0.03 catches
98	 *  even subtle frames while leaving headroom for mesh noise. */
99	const OBSTACLE_Y_DELTA_M = 0.03;
100	/** Negative delta — a probe sitting LOWER than the centre by this much is
101	 *  also treated as an obstacle (recessed skylight glass, gap between tile
102	 *  and frame, missing tile). Tighter than the positive threshold because
103	 *  natural slope curvature only goes up. */
104	const OBSTACLE_Y_DELTA_NEG_M = 0.03;
105	/** Extra margin around the panel footprint when probing for obstacles —
106	 *  guarantees adjacent obstacles still flag the panel even if the corner
107	 *  itself was clean. */
108	const OBSTACLE_PROBE_MARGIN_M = 0.18;
109	/** Extra margin around analysis.json obstructions (chimneys, dormers, vents). */
110	const OBSTRUCTION_MARGIN_M = 0.45;
111	/** Overlap factor — panels can be ALMOST flush (12 % gap of the short
112	 *  side) but never sit on top of each other. */
113	const PANEL_OVERLAP_FACTOR = 0.88;
114	/** Sampling grid step as a fraction of panel size — used ONLY for the
115	 *  initial face-discovery scan. Smaller = denser detection of the roof
116	 *  pitches. The actual placement grid is aligned per-face on the panel
117	 *  pitch. */
118	const GRID_STEP_RATIO = 0.55;
119	/** External padding applied to each detected face polygon BEFORE the grid
120	 *  is laid down — guarantees panels never overhang the eave or ridge.
121	 *  Real installations leave ~30 cm clearance for snow guards and rails. */
122	const FACE_EXTERNAL_PADDING_M = 0.35;
123	/** Visible gap between adjacent panel cells (real PV arrays have rail
124	 *  joiners + thermal expansion gap of ~2–4 cm). Bumping to 5 cm gives a
125	 *  clear silhouette for each module on screen. */
126	const CELL_GAP_M = 0.05;
127	/** A grid cell is considered "covered" by the discovery scan if it lies
128	 *  within this distance of at least one sample hit on its cluster. Acts
129	 *  as an implicit polygon test for L-shaped or irregular faces. */
130	const CELL_COVERAGE_RADIUS_RATIO = 0.85;
131	const UP = new Vector3(0, 1, 0);
132	
133	interface ProjectedPanel {
134	  faceId: number;
135	  x: number;
136	  y: number;
137	  z: number;
138	  normal: [number, number, number];
139	  quaternion: Quaternion;
140	}
141	
142	interface PanelLayout {
143	  panels: ProjectedPanel[];
144	  variant: PanelVariant;
145	}
146	
147	export function Panels() {
148	  const design = useStore((s) => s.design);
149	  const placedCount = useStore((s) => s.placedCount);
150	  // Wait for `glbStable` (post-morph) — not just `glbLoaded` (mounted) —
151	  // before doing any raycast-based projection. This guarantees the GLB is
152	  // at full opacity AND its world matrix has settled (the morph animates
153	  // the parent group's scale 0.6 → 1.0).
154	  const glbStable = useStore((s) => s.glbStable);
155	  const glbHeight = useStore((s) => s.glbHeight);
156	  const { modulePositions: recenteredPositions, obstructions } =
157	    useHouseGeometry();
158	  const sceneRoot = useThree((s) => s.scene);
159	
160	  const glbRoofAreaM2 = useStore((s) => s.glbRoofAreaM2);
161	
162	  // Variant cascade: try the brand-recommended full-size first, then fall
163	  // back to smaller form factors for tighter roofs. The algorithm uses the
164	  // first variant that hits ≥ the target kWp.
165	  const variants: PanelVariant[] = useMemo(() => {
166	    const full =
167	      design?.moduleBrand === 'Trina'
168	        ? PANEL_VARIANT_FULL_TRINA
169	        : PANEL_VARIANT_FULL_AIKO;
170	    return [full, PANEL_VARIANT_COMPACT, PANEL_VARIANT_MINI];
171	  }, [design?.moduleBrand]);
172	
173	  // Pre-pick the most appropriate variant given the actual roof area on the
174	  // GLB. We compute, for each variant, the m² of roof needed to cover the
175	  // k-NN target kWp; the first variant whose footprint fits within the
176	  // packing-efficiency-adjusted roof area is the one we'll start with.
177	  // Falls through to the smallest if none fit (rare on real homes).
178	  // Packing efficiency 0.45 accounts for: only ~50% of the roof is south-
179	  // facing, then 80-90% of THAT is reachable after edges & obstacles.
180	  const PACKING_EFFICIENCY = 0.45;
181	  const preferredVariant = useMemo<PanelVariant>(() => {
182	    if (!design || !glbRoofAreaM2) return variants[0];
183	    const targetKwp = design.totalKwp || 0;
184	    const usableM2 = glbRoofAreaM2 * PACKING_EFFICIENCY;
