1	// k-NN sizing engine — OWNED by Dev B
2	// In-memory over the Reonic dataset (1620 status_quo rows × ~20 BOM line items each).
3	// Primary source of truth for kWp / kWh / heatpump / similar-projects in /api/design.
4	//
5	// Data convention (Reonic CSVs):
6	// - All energy columns are stored in Wh (e.g. energy_demand_wh = 4_500_000 → 4500 kWh)
7	// - All "_kwh" / "_kw" columns are ALSO stored in Wh / W (e.g. battery_capacity_kwh = 12_000 → 12 kWh)
8	// - module_watt_peak is in W per panel (e.g. 475 → 475 Wp)
9	// We normalize everything to kWh / kW internally.
10	
11	import fs from 'node:fs';
12	import path from 'node:path';
13	import type { CustomerProfile, DesignResult, SimilarProject } from './types';
14	
15	export interface ProjectRow {
16	  projectId: string;
17	  // Inputs (from status_quo)
18	  energyDemandKwh: number;
19	  hasEv: number;          // 0/1
20	  evKm: number;
21	  heatingType: number;    // 0=oil, 1=gas, 2=heatpump, 3=other
22	  houseSizeSqm: number;
23	  inhabitants: number;
24	  // Outputs (aggregated from options_parts, option_number=1)
25	  totalKwp: number;
26	  batteryKwh: number;
27	  hasHeatPump: number;
28	  heatPumpKw: number;
29	  hasWallbox: number;
30	}
31	
32	const HEATING_MAP: Record<string, number> = {
33	  Oil: 0,
34	  oil: 0,
35	  Gas: 1,
36	  gas: 1,
37	  Heatpump: 2,
38	  heatpump: 2,
39	  OtherNonRenewable: 3,
40	  other: 3,
41	};
42	
43	let PROJECTS: ProjectRow[] | null = null;
44	let MEAN: number[] = [];
45	let STD: number[] = [];
46	
47	// --- CSV parser (tolerant, no quoted commas in this dataset) ---
48	function parseCsv(content: string): Record<string, string>[] {
49	  const lines = content.replace(/\r/g, '').trim().split('\n');
50	  if (lines.length === 0) return [];
51	  const headers = lines[0].split(',');
52	  return lines.slice(1).map((line) => {
53	    const fields = line.split(',');
54	    const row: Record<string, string> = {};
55	    for (let i = 0; i < headers.length; i++) row[headers[i]] = fields[i] ?? '';
56	    return row;
57	  });
58	}
59	
60	function num(s: string | undefined): number {
61	  if (!s) return 0;
62	  const v = parseFloat(s);
63	  return Number.isFinite(v) ? v : 0;
64	}
65	
66	function loadProjects(): ProjectRow[] {
67	  if (PROJECTS) return PROJECTS;
