36	  houseId: HouseId | 'custom';
37	  profile?: CustomerProfile;
38	  lat?: number;
39	  lng?: number;
40	  address?: string;
41	}
42	
43	function isSouthish(azimuthDeg: number): boolean {
44	  return azimuthDeg > 90 && azimuthDeg < 270;
45	}
46	
47	async function loadBakedGeometry(houseId: HouseId): Promise<RoofGeometry> {
48	  const filePath = path.join(process.cwd(), 'public', 'baked', `${houseId}-analysis.json`);
49	  const raw = await fs.readFile(filePath, 'utf-8');
50	  return JSON.parse(raw) as RoofGeometry;
51	}
52	
53	export async function POST(req: NextRequest) {
54	  const t0 = performance.now();
55	
56	  let body: DesignRequestBody;
57	  try {
58	    body = (await req.json()) as DesignRequestBody;
59	  } catch {
60	    return NextResponse.json({ error: 'Invalid JSON body' }, { status: 400 });
61	  }
62	  const { houseId } = body;
63	  if (!houseId) {
64	    return NextResponse.json({ error: 'Missing houseId' }, { status: 400 });
65	  }
66	
67	  // 1. Resolve profile (provided, or inferred for custom)
68	  let profile: CustomerProfile | undefined = body.profile;
69	  if (!profile && houseId === 'custom') {
70	    profile = inferProfileFromLocation(body.lat, body.lng);
71	  }
72	  if (!profile) {
73	    return NextResponse.json({ error: 'Missing profile' }, { status: 400 });
74	  }
75	
76	  // 2. Resolve roof geometry
77	  let roof: RoofGeometry;
78	  let synthesised = false;
79	  if (houseId === 'custom') {
80	    roof = synthesiseRoofGeometry(body.lat ?? 0, body.lng ?? 0, profile.houseSizeSqm);
81	    synthesised = true;
82	  } else {
83	    try {
84	      roof = await loadBakedGeometry(houseId);
85	    } catch {
86	      return NextResponse.json(
87	        { error: `No analysis.json for house "${houseId}"` },
88	        { status: 404 },
89	      );
90	    }
91	  }
92	
93	  // 3. Compute the maximum solar capacity the roof can host (south-ish faces only).
94	  //    isJumelee → divide by 2 (shared roof with neighbour).
95	  const houseShareDivisor = profile.isJumelee ? 2 : 1;
96	  const southFaces = roof.faces.filter((f) => isSouthish(f.azimuth));
97	  const rawRoofMaxKwp =
98	    southFaces.reduce((sum, f) => sum + f.usableArea * PANEL_EFFICIENCY, 0)
99	    || roof.faces.reduce((sum, f) => sum + f.usableArea * PANEL_EFFICIENCY, 0);
100	  const roofMaxKwp = rawRoofMaxKwp / houseShareDivisor;
101	
102	  // 4. k-NN sizing on the 1620 Reonic projects
103	  const reco = await recommendSystem(profile, roofMaxKwp);
104	
105	  // 5. Module count + inverter sizing
106	  const moduleCount = Math.max(1, Math.round((reco.totalKwp * 1000) / MODULE_WATT_PEAK));
107	  const inverterPowerKw = Math.max(1, Math.ceil(reco.totalKwp * 0.85));
